def _load_config():
    """
    Читает config.ini рядом с .exe (или рядом с app.py в dev-режиме).
    Все параметры можно переопределить — пересборка .exe не нужна.

    Пример config.ini:
        [app]
        network_path = \\\\server\\share\\email-builder
        port = 8080
    """
    import configparser

    if getattr(sys, 'frozen', False):
        config_dir = os.path.dirname(sys.executable)
    else:
        config_dir = os.path.dirname(os.path.abspath(__file__))

    config_path = os.path.join(config_dir, 'config.ini')

    cfg = configparser.ConfigParser()
    # Try UTF-8 first; fall back to Windows-1251 (common on Russian Windows installations).
    try:
        cfg.read(config_path, encoding='utf-8')
    except UnicodeDecodeError:
        cfg = configparser.ConfigParser()
        cfg.read(config_path, encoding='cp1251')

    section = 'app'
    defaults = {
        'port': '8080',
    }

    def get(key):
        if key == 'network_path':
            if sys.platform == 'win32':
                # Windows — берём network_path_win или fallback на network_path
                val = cfg.get(section, 'network_path_win', fallback=None)
                if not val:
                    val = cfg.get(section, 'network_path', fallback=None)
                if not val:
                    raise RuntimeError(
                        f"Не найден параметр network_path_win в {config_path}\n"
                        "Добавьте в config.ini:\n"
                        "[app]\n"
                        "network_path_win = \\\\server\\share\\email-builder"
                    )
                return val
            else:
                # Linux — автопоиск, путь найдём позже в main()
                # Возвращаем smb path как placeholder
                val = cfg.get(section, 'network_path_smb', fallback=None)
                if not val:
                    val = cfg.get(section, 'network_path', fallback=None)
                if not val:
                    raise RuntimeError(
                        f"Не найден параметр network_path_smb в {config_path}\n"
                        "Добавьте в config.ini:\n"
                        "[app]\n"
                        "network_path_smb = //server/share/email-builder"
                    )
                return val
        return cfg.get(section, key, fallback=defaults.get(key, ''))

    return (
        get('network_path'),
        int(get('port')),
        config_path,
        cfg.get(section, 'network_path_linux_hint', fallback='email-builder'),
        cfg.get(section, 'network_path_smb', fallback=None),
        cfg.get(section, 'network_path_linux_resolved', fallback=None),
        cfg.get(section, 'exchange_server', fallback='').strip(),
    )


try:
    (NETWORK_RESOURCES_PATH, PORT, _CONFIG_PATH, _LINUX_HINT,
     _SMB_PATH, _LINUX_RESOLVED, _DEFAULT_EXCHANGE_SERVER) = _load_config()
except RuntimeError as _cfg_err:
    try:
        from PyQt5.QtWidgets import QApplication, QMessageBox
        _app = QApplication.instance() or QApplication(sys.argv)
        QMessageBox.critical(None, 'Почтелье — ошибка конфигурации', str(_cfg_err))
    except Exception:
        pass
    sys.exit(1)


def _resolve_app_mode():
    """
    Determines the startup mode by validating the ``.lic`` token file.

    Hash source
        The expected SHA-256 hash is read from ``.admin_hash`` — a file
        embedded into the executable at build time via ``build.spec``.
        In dev mode it is read from the project root.

    ``.lic`` location
        Must be placed next to the ``.exe`` (or next to ``app.py`` in dev).
        Filename is exactly ``.lic`` — no stem, only extension.

    Resolution rules:

    * No ``.lic`` found                  → ``'user'``, silently.
    * ``.lic`` found, no ``.admin_hash`` → ``'user'``, silently
                                           (build without admin support).
    * ``.lic`` found, hash matches       → ``'admin'``.
    * ``.lic`` found, hash mismatch      → ``'user'``,
                                           sets ``_INVALID_TOKEN = True``.

    :returns: ``'admin'`` or ``'user'``
    """
    import hashlib

    global _INVALID_TOKEN

    # Directory where .lic lives (next to the exe or next to app.py in dev)
    if getattr(sys, 'frozen', False):
        exe_dir    = os.path.dirname(sys.executable)
        bundle_dir = sys._MEIPASS
    else:
        exe_dir = bundle_dir = os.path.dirname(os.path.abspath(__file__))

    lic_path  = os.path.join(exe_dir,    '.lic')
    hash_path = os.path.join(bundle_dir, '.admin_hash')

    if not os.path.exists(lic_path):
        return 'user'

    if not os.path.exists(hash_path):
        # Built without admin support — silently ignore .lic
        return 'user'

    try:
        secret        = open(lic_path,  'r', encoding='utf-8').read().strip()
        expected_hash = open(hash_path, 'r', encoding='utf-8').read().strip().lower()
        actual_hash   = hashlib.sha256(secret.encode('utf-8')).hexdigest()
        if actual_hash == expected_hash:
            return 'admin'
        print('[license] token mismatch — running in user mode')
        _INVALID_TOKEN = True
        return 'user'
    except Exception as _e:
        print(f'[license] read error: {_e}')
        _INVALID_TOKEN = True
        return 'user'


_INVALID_TOKEN   = False
_ADMIN_VALIDATED = False
APP_MODE = _resolve_app_mode()
