def get_cache_version():
    """Получить версию локального кеша"""
    try:
        if os.path.exists(CACHE_VERSION_FILE):
            with open(CACHE_VERSION_FILE, 'r', encoding='utf-8') as f:
                return f.read().strip()
        return None
    except Exception as e:
        print(f"⚠️  Ошибка чтения версии кеша: {e}")
        return None


def get_network_version():
    """Получить версию с сетевого ресурса"""
    try:
        if os.path.exists(NETWORK_VERSION_FILE):
            with open(NETWORK_VERSION_FILE, 'r', encoding='utf-8') as f:
                version = f.read().strip()
                return version if version else None
        else:
            # Файл version.txt не существует на сервере
            return None
    except Exception as e:
        print(f"⚠️  Ошибка чтения version.txt: {e}")
        return None


def set_cache_version(version):
    """Сохранить версию кеша"""
    try:
        with open(CACHE_VERSION_FILE, 'w', encoding='utf-8') as f:
            f.write(version)
        print(f"✓ Версия кеша обновлена: {version}")
    except Exception as e:
        print(f"⚠️  Ошибка записи версии: {e}")


def _bump_network_version() -> Optional[str]:
    """Write a new timestamp-based version string to the network version file.

    Called by admin routes whenever shared repo content changes (resource
    upload/delete, template save/update/delete/rename, category changes).
    Also records the mutation timestamp so the background repo scanner can
    distinguish UI-initiated changes from external filesystem modifications.

    :returns: New version string on success, ``None`` on I/O error.
    """
    global _admin_mutation_ts
    new_version = time.strftime('%Y%m%d.%H%M%S')
    try:
        with open(NETWORK_VERSION_FILE, 'w', encoding='utf-8') as f:
            f.write(new_version)
        _admin_mutation_ts = time.time()
        print(f'✓ Версия репозитория обновлена: {new_version}')
        return new_version
    except Exception as e:
        print(f'⚠️  Ошибка записи версии репозитория: {e}')
        return None


# Lock that prevents concurrent cache initialisation (startup + background updater).
_cache_init_lock = threading.Lock()

# Timestamp of the last admin-UI repo mutation; used by the repo scanner to
# suppress false-positive "external change" detections.
_admin_mutation_ts: float = 0.0


def check_network_access():
    """Checks that NETWORK_RESOURCES_PATH exists and is a valid resource repo."""
    ok, _ = _validate_resource_repo(NETWORK_RESOURCES_PATH)
    return ok


def _validate_resource_repo(path):
    """
    Checks whether *path* contains a valid Почтелье resource repository.

    A valid repository must have:
        * ``version.txt``    — version marker at the root
        * ``static/``        — resources directory

    :param path: Absolute path to check.
    :returns: ``(True, '')`` if valid,
              ``(False, reason)`` if the directory exists but is not a repo,
              ``(False, reason)`` if the directory does not exist.
    """
    if not path or not os.path.exists(path):
        return False, 'Путь не существует'
    if not os.path.isdir(path):
        return False, 'Путь не является директорией'
    if not os.path.exists(os.path.join(path, 'version.txt')):
        return False, 'Не найден файл version.txt — это не репозиторий ресурсов'
    if not os.path.isdir(os.path.join(path, 'static')):
        return False, 'Не найдена папка static/ — репозиторий неполный'
    return True, ''


