# Вставить base64 гифки сюда (одна длинная строка или многострочная)
_SPLASH_GIF_B64 = """

"""


def show_splash(main_logic):
    try:
        from PyQt5.QtWidgets import QApplication, QWidget, QLabel, QVBoxLayout
        from PyQt5.QtCore import (
            Qt, QEventLoop, QThread, pyqtSignal, QBuffer, QIODevice, QByteArray,
            QTimer, QRectF,
        )
        from PyQt5.QtGui import QMovie, QIcon, QFont, QColor, QPainter, QPen, QBrush
        import math

        global _qt_app
        if not QApplication.instance():
            QApplication.setAttribute(Qt.AA_ShareOpenGLContexts)
            QApplication.setAttribute(Qt.AA_EnableHighDpiScaling)
            QApplication.setAttribute(Qt.AA_UseHighDpiPixmaps)
        _qt_app = QApplication.instance() or QApplication(sys.argv)

        W, H = 320, 320

        # ── Спиннер ──────────────────────────────────────────────────────
        class _Spinner(QWidget):
            N = 12
            OFFSET = 30
            RECT_W = 20
            RECT_H = 7
            CORNER_R = 2.5
            MARGIN_R = 10
            MARGIN_T = 10
            SPEED_MS = 50

            def __init__(self, parent=None):
                super().__init__(parent)
                self._step = 0
                sz = (self.OFFSET + self.RECT_W) * 2 + 4
                self.setFixedSize(sz, sz)
                self.setAttribute(Qt.WA_TransparentForMouseEvents)
                self.setAttribute(Qt.WA_NoSystemBackground)
                self.setAttribute(Qt.WA_TranslucentBackground)
                self._timer = QTimer(self)
                self._timer.timeout.connect(self._tick)
                self._timer.start(self.SPEED_MS)

            def _tick(self):
                self._step = (self._step + 1) % self.N
                self.update()

            def paintEvent(self, event):
                painter = QPainter(self)
                painter.setRenderHint(QPainter.Antialiasing)
                cx = self.width() / 2
                cy = self.height() / 2
                for i in range(self.N):
                    deg = i * 360.0 / self.N
                    rad = math.radians(deg)
                    rx = cx + math.cos(rad) * self.OFFSET
                    ry = cy + math.sin(rad) * self.OFFSET
                    alpha = int(
                        255 * (((i - self._step) % self.N + 1) / self.N))
                    painter.save()
                    painter.translate(rx, ry)
                    painter.rotate(deg)
                    color = QColor(255, 255, 255, alpha)
                    painter.setBrush(QBrush(color))
                    painter.setPen(Qt.NoPen)
                    rect = QRectF(
                        -self.RECT_W / 2,
                        -self.RECT_H / 2,
                        self.RECT_W,
                        self.RECT_H,
                    )
                    painter.drawRoundedRect(rect, self.CORNER_R, self.CORNER_R)
                    painter.restore()
                painter.end()

        # ── Основное окно ─────────────────────────────────────────────────
        splash = QWidget(None, Qt.FramelessWindowHint |
                         Qt.WindowStaysOnTopHint)
        splash.setAttribute(Qt.WA_TranslucentBackground)
        splash.setFixedSize(W, H)

        # Скруглённые углы через bitmap-маску
        from PyQt5.QtGui import QRegion, QPainterPath
        path = QPainterPath()
        path.addRoundedRect(0, 0, W, H, 16, 16)
        region = QRegion(path.toFillPolygon().toPolygon())
        splash.setMask(region)

        screen_geo = _qt_app.primaryScreen().geometry()
        splash.move(
            (screen_geo.width() - W) // 2,
            (screen_geo.height() - H) // 2,
        )
        splash.setObjectName('splashRoot')
        splash.setStyleSheet('''
            QWidget#splashRoot {
                background-color: rgba(10, 10, 10, 235);
                border-radius: 16px;
            }
        ''')

        # Без layout — всё абсолютное позиционирование поверх GIF
        layout = QVBoxLayout(splash)
        layout.setContentsMargins(0, 0, 0, 0)
        layout.setSpacing(0)

        # GIF на весь размер окна
        gif_label = QLabel(splash)
        gif_label.setAlignment(Qt.AlignCenter)
        gif_label.setFixedSize(W, H)
        gif_label.setStyleSheet('background: transparent;')

        try:
            gif_data = base64.b64decode(_SPLASH_GIF_B64.strip())
            _buf = QBuffer()
            _buf.setData(QByteArray(gif_data))
            _buf.open(QIODevice.ReadOnly)
            movie = QMovie()
            movie.setDevice(_buf)
            movie.setScaledSize(gif_label.size())
            gif_label.setMovie(movie)
            movie.start()
            gif_label._buf = _buf
            gif_label._movie = movie
        except Exception:
            gif_label.setText('Почтелье')
            gif_label.setStyleSheet(
                'color: white; font-size: 22px; background: transparent;')

        layout.addWidget(gif_label)

        # Название — поверх GIF внизу по центру
        title_lbl = QLabel('Почтелье', splash)
        title_lbl.setAlignment(Qt.AlignCenter)
        title_lbl.setFont(QFont('Segoe UI', 24, QFont.Bold))
        title_lbl.setStyleSheet('''
            color: white;
            background: transparent;
        ''')
        title_lbl.setFixedWidth(W)
        title_lbl.move(0, H - 68)

        # Статус — поверх GIF под названием
        status_lbl = QLabel('Запуск...', splash)
        status_lbl.setAlignment(Qt.AlignCenter)
        status_lbl.setFont(QFont('Segoe UI', 14))
        status_lbl.setStyleSheet('''
            color: rgba(255,255,255,200);
            background: transparent;
        ''')
        status_lbl.setFixedWidth(W)
        status_lbl.move(0, H - 36)

        # Спиннер — правый верхний угол
        spinner = _Spinner(splash)
        sz = spinner.width()
        spinner.move(
            W - sz - _Spinner.MARGIN_R,
            _Spinner.MARGIN_T,
        )
        spinner.raise_()
        spinner.show()
        title_lbl.raise_()
        status_lbl.raise_()

        try:
            if getattr(sys, 'frozen', False):
                ico = os.path.join(sys._MEIPASS, 'icon.ico')
            else:
                ico = os.path.join(os.path.dirname(__file__), 'icon.ico')
            if os.path.exists(ico):
                splash.setWindowIcon(QIcon(ico))
        except Exception:
            pass

        loop = QEventLoop()

        class _Worker(QThread):
            done = pyqtSignal()
            status_changed = pyqtSignal(str)

            def run(self):
                try:
                    main_logic(self.done.emit, self.status_changed.emit)
                except Exception as exc:
                    print(f'[splash worker] {exc}')
                    self.done.emit()

        _worker = _Worker()
        _worker.done.connect(lambda: (splash.close(), loop.quit()))
        _worker.status_changed.connect(status_lbl.setText)
        _worker.start()

        splash.show()
        loop.exec_()

    except Exception as e:
        print(f'[show_splash] {e}')
        main_logic(lambda: None, lambda text: None)


def _save_resolved_linux_path(path):
    """Saves the resolved local path of the network share to config.ini."""
    import configparser
    cfg = configparser.ConfigParser()
    cfg.read(_CONFIG_PATH, encoding='utf-8')
    if 'app' not in cfg:
        cfg['app'] = {}
    cfg['app']['network_path_linux_resolved'] = path
    with open(_CONFIG_PATH, 'w', encoding='utf-8') as f:
        cfg.write(f)


def _save_network_path(path):
    """Saves the resolved network resource path to config.ini (platform-aware)."""
    import configparser
    cfg = configparser.ConfigParser()
    cfg.read(_CONFIG_PATH, encoding='utf-8')
    if 'app' not in cfg:
        cfg['app'] = {}
    if sys.platform == 'win32':
        cfg['app']['network_path_win'] = path
    else:
        cfg['app']['network_path_linux_resolved'] = path
    with open(_CONFIG_PATH, 'w', encoding='utf-8') as f:
        cfg.write(f)


def _read_app_config():
    """Read ``config.ini`` using the same encoding strategy as startup config."""
    import configparser

    cfg = configparser.ConfigParser()
    try:
        cfg.read(_CONFIG_PATH, encoding='utf-8')
    except UnicodeDecodeError:
        cfg = configparser.ConfigParser()
        cfg.read(_CONFIG_PATH, encoding='cp1251')

    if 'app' not in cfg:
        cfg['app'] = {}
    return cfg


def _write_app_config(cfg):
    """Persist ``config.ini`` in UTF-8."""
    with open(_CONFIG_PATH, 'w', encoding='utf-8') as f:
        cfg.write(f)


def _get_repo_setting_meta():
    """Return the platform-relevant config key and placeholder for repo path."""
    if sys.platform == 'win32':
        return {
            'platform': 'win32',
            'platform_label': 'Windows',
            'repo_key': 'network_path_win',
            'repo_label': 'Путь к репозиторию ресурсов',
            'placeholder': r'\\server\share\email-builder',
        }

    return {
        'platform': sys.platform,
        'platform_label': 'Linux',
        'repo_key': 'network_path_linux_resolved',
        'repo_label': 'Локальный путь к смонтированному репозиторию',
        'placeholder': '/mnt/share/email-builder',
    }


def _get_runtime_repo_path():
    """Return the currently active repository path for this platform."""
    if sys.platform == 'win32':
        return NETWORK_RESOURCES_PATH
    return _LINUX_RESOLVED or NETWORK_RESOURCES_PATH


def _apply_repo_path(path, persist=False):
    """Apply a new repository path at runtime and optionally save it."""
    global NETWORK_RESOURCES_PATH, NETWORK_VERSION_FILE, _LINUX_RESOLVED

    cleaned = str(path or '').strip()
    NETWORK_RESOURCES_PATH = cleaned
    NETWORK_VERSION_FILE = os.path.join(cleaned, 'version.txt') if cleaned else ''

    if sys.platform != 'win32':
        _LINUX_RESOLVED = cleaned

    if persist and cleaned:
        cfg = _read_app_config()
        cfg['app'][_get_repo_setting_meta()['repo_key']] = cleaned
        _write_app_config(cfg)


def _search_for_resource_any(status_cb=None):
    """Search for the resource repo using sensible defaults for the platform."""
    found = _search_for_resource('network', _LINUX_HINT, _SMB_PATH, status_cb=status_cb)
    if found:
        return found
    if sys.platform == 'win32':
        return _search_for_resource('local', _LINUX_HINT, _SMB_PATH, status_cb=status_cb)
    return None


def _search_for_resource(mode, hint, smb_path, status_cb=None):
    """
    Searches for the resource directory.

    :param mode: ``'network'`` scans mounted network shares/drives;
                 ``'local'`` scans fixed local drives.
    :param hint: Folder name to locate (e.g. ``'email-builder'``).
    :param smb_path: SMB URL used on Linux for kio/gvfs mount attempts.
    :param status_cb: Optional callable(str) for progress messages.
    :returns: Absolute path string if found, otherwise ``None``.
    """
    def status(msg):
        print(msg)
        if status_cb:
            status_cb(msg)

    if sys.platform != 'win32':
        return find_or_mount_linux_path(smb_path, hint=hint,
                                        status_callback=status_cb)

    # Windows ----------------------------------------------------------------
    if mode == 'network':
        status('Поиск на подключённых сетевых ресурсах...')
        import subprocess
        checked = set()

        # Strategy 1: paths reported by "net use"
        try:
            flags = getattr(subprocess, 'CREATE_NO_WINDOW', 0)
            out = subprocess.check_output(
                ['net', 'use'], text=True, stderr=subprocess.DEVNULL,
                creationflags=flags,
            )
            for line in out.splitlines():
                for part in line.split():
                    if part.startswith('\\\\') and part not in checked:
                        checked.add(part)
                        candidate = os.path.join(part, hint)
                        if os.path.exists(candidate):
                            status(f'Найдено: {candidate}')
                            return candidate
        except Exception as _e:
            print(f'[search] net use: {_e}')

        # Strategy 2: drive letters of type DRIVE_REMOTE (4)
        try:
            import ctypes
            for letter in 'ABCDEFGHIJKLMNOPQRSTUVWXYZ':
                drive = f'{letter}:\\'
                if ctypes.windll.kernel32.GetDriveTypeW(drive) == 4:
                    if drive not in checked:
                        checked.add(drive)
                        for root, dirs, _ in os.walk(drive):
                            if hint in dirs:
                                found = os.path.join(root, hint)
                                status(f'Найдено: {found}')
                                return found
                            if root[len(drive):].count(os.sep) >= 4:
                                dirs.clear()
        except Exception as _e:
            print(f'[search] drive scan: {_e}')

    else:  # local
        status('Поиск в локальных папках...')
        try:
            import ctypes
            for letter in 'ABCDEFGHIJKLMNOPQRSTUVWXYZ':
                drive = f'{letter}:\\'
                if ctypes.windll.kernel32.GetDriveTypeW(drive) in (3, 6):
                    for root, dirs, _ in os.walk(drive):
                        if hint in dirs:
                            found = os.path.join(root, hint)
                            status(f'Найдено: {found}')
                            return found
                        if root[len(drive):].count(os.sep) >= 5:
                            dirs.clear()
        except Exception as _e:
            print(f'[search] local scan: {_e}')

    status('Ресурс не найден')
    return None


def _init_new_resource_catalog(path):
    """
    Initialises an empty resource catalog at *path*.

    Creates the ``static/`` subdirectory, a ``version.txt`` marker, and
    copies the built-in ``config.json`` template when available.
    Admin-only feature.

    :param path: Absolute path for the new catalog root.
    :returns: ``True`` on success, ``False`` on error.
    """
    import time as _time
    try:
        os.makedirs(os.path.join(path, 'static'), exist_ok=True)
        version = _time.strftime('%Y%m%d.1')
        with open(os.path.join(path, 'version.txt'), 'w', encoding='utf-8') as _f:
            _f.write(version)
        builtin_cfg = os.path.join(BUILTIN_DIR, 'static', 'config.json')
        dst_cfg = os.path.join(path, 'static', 'config.json')
        if os.path.exists(builtin_cfg):
            import shutil as _sh
            _sh.copy2(builtin_cfg, dst_cfg)
        else:
            with open(dst_cfg, 'w', encoding='utf-8') as _f:
                _f.write('{}')
        print(f'✓ Новый каталог ресурсов создан: {path} (версия {version})')
        return True
    except Exception as _e:
        print(f'❌ Ошибка создания каталога: {_e}')
        return False


def _show_resource_finder_dialog(is_admin, reason=''):
    """
    Modal Qt dialog shown when the configured resource path is inaccessible
    or does not contain a valid resource repository.

    Provides:

    * A path input field pre-filled with the current ``NETWORK_RESOURCES_PATH``.
    * A "Verify path" button that validates the path as a resource repository.
    * A search-mode toggle ("Network" / "Local") with an explanatory note.
    * A "Search" button that scans available shares/drives in a background thread.
    * A "Create new" button (admin-only) that initialises a fresh resource catalog.

    :param is_admin: When ``True``, the "Create new" button is shown.
    :param reason: Human-readable explanation of why the current path failed.
    :returns: Accepted path string, or ``None`` if the user cancelled.
    """
    from PyQt5.QtWidgets import (
        QApplication, QDialog, QVBoxLayout, QHBoxLayout, QLabel,
        QLineEdit, QPushButton, QRadioButton, QButtonGroup, QGroupBox,
        QProgressBar, QFrame,
    )
    from PyQt5.QtCore import Qt, QThread, pyqtSignal
    from PyQt5.QtGui import QFont

    class _SearchWorker(QThread):
        status_update = pyqtSignal(str)
        result_ready  = pyqtSignal(str)

        def __init__(self, mode, hint, smb_path):
            super().__init__()
            self._mode     = mode
            self._hint     = hint
            self._smb_path = smb_path

        def run(self):
            found = _search_for_resource(
                self._mode, self._hint, self._smb_path,
                status_cb=lambda m: self.status_update.emit(m),
            )
            self.result_ready.emit(found or '')

    qt_app = QApplication.instance() or QApplication(sys.argv)  # noqa: F841

    dlg = QDialog()
    dlg.setWindowTitle('Почтелье — поиск ресурсов')
    dlg.setMinimumWidth(580)
    dlg.setModal(True)

    layout = QVBoxLayout(dlg)
    layout.setSpacing(10)

    # Info -------------------------------------------------------------------
    reason_text = f'<br><i style="color:#b45309">{reason}</i>' if reason else ''
    current_repo_path = _get_runtime_repo_path() or ''
    if sys.platform == 'win32':
        expected_param = 'network_path_win'
        browse_placeholder = r'\\server\share\email-builder'
    else:
        expected_param = 'network_path_linux_resolved'
        browse_placeholder = '/mnt/share/email-builder'

    shown_path = current_repo_path or 'не указан'
    info_lbl = QLabel(
        f'Репозиторий ресурсов не обнаружен по пути из параметра '
        f'<b>{expected_param}</b>:<br>'
        f'<b>{shown_path}</b>'
        f'{reason_text}<br><br>'
        f'Укажите корректный путь вручную или воспользуйтесь автоматическим поиском.'
    )
    info_lbl.setTextFormat(Qt.RichText)
    info_lbl.setWordWrap(True)
    layout.addWidget(info_lbl)

    sep = QFrame()
    sep.setFrameShape(QFrame.HLine)
    sep.setFrameShadow(QFrame.Sunken)
    layout.addWidget(sep)

    # Path input -------------------------------------------------------------
    layout.addWidget(QLabel('Путь к каталогу ресурсов:'))
    path_row = QHBoxLayout()
    path_edit = QLineEdit(current_repo_path)
    path_edit.setPlaceholderText(browse_placeholder)
    btn_browse = QPushButton('Выбрать папку')
    path_row.addWidget(path_edit, 1)
    path_row.addWidget(btn_browse)
    layout.addLayout(path_row)

    # Verify row -------------------------------------------------------------
    verify_row = QHBoxLayout()
    btn_verify    = QPushButton('Проверить путь')
    verify_status = QLabel('')
    verify_row.addWidget(btn_verify)
    verify_row.addWidget(verify_status)
    verify_row.addStretch()
    layout.addLayout(verify_row)

    # Search mode ------------------------------------------------------------
    mode_box    = QGroupBox('Режим поиска')
    mode_layout = QHBoxLayout(mode_box)
    rb_network  = QRadioButton('В сети')
    rb_local    = QRadioButton('Локально')
    rb_local.setChecked(True)
    btn_grp = QButtonGroup(dlg)
    btn_grp.addButton(rb_network)
    btn_grp.addButton(rb_local)
    mode_layout.addWidget(rb_network)
    mode_layout.addWidget(rb_local)
    note_lbl = QLabel(
        'Поиск «В сети» сканирует только уже подключённые сетевые ресурсы.'
    )
    note_lbl.setFont(QFont('Segoe UI', 8))
    note_lbl.setWordWrap(True)
    mode_layout.addWidget(note_lbl, stretch=1)
    layout.addWidget(mode_box)

    # Search button + progress -----------------------------------------------
    btn_search    = QPushButton('Выполнить поиск')
    search_status = QLabel('')
    search_status.setWordWrap(True)
    progress = QProgressBar()
    progress.setRange(0, 0)
    progress.setVisible(False)
    layout.addWidget(btn_search)
    layout.addWidget(search_status)
    layout.addWidget(progress)

    # Bottom buttons ---------------------------------------------------------
    btn_row    = QHBoxLayout()
    btn_ok     = QPushButton('Применить')
    btn_cancel = QPushButton('Отмена')
    btn_ok.setEnabled(False)
    btn_row.addStretch()
    if is_admin:
        btn_create = QPushButton('Создать новый')
        btn_row.addWidget(btn_create)
    btn_row.addWidget(btn_ok)
    btn_row.addWidget(btn_cancel)
    layout.addLayout(btn_row)

    _worker = [None]
    _result  = [None]

    # Verify -----------------------------------------------------------------
    def _do_verify():
        p = path_edit.text().strip()
        ok, reason_v = _validate_resource_repo(p)
        if ok:
            verify_status.setText('✓ Репозиторий найден')
            verify_status.setStyleSheet('color: green')
            btn_ok.setEnabled(True)
        else:
            verify_status.setText(f'✗ {reason_v}')
            verify_status.setStyleSheet('color: #b45309')
            btn_ok.setEnabled(False)

    btn_verify.clicked.connect(_do_verify)
    path_edit.textChanged.connect(lambda _: (
        verify_status.setText(''),
        btn_ok.setEnabled(False),
    ))

    def _do_browse():
        raw = path_edit.text().strip()
        start_dir = raw
        if raw and not os.path.isdir(start_dir):
            start_dir = os.path.dirname(raw)
        if not start_dir or not os.path.isdir(start_dir):
            if sys.platform == 'win32':
                start_dir = os.path.expanduser('~')
            else:
                for candidate in ('/mnt', '/media', os.path.expanduser('~')):
                    if os.path.isdir(candidate):
                        start_dir = candidate
                        break
        chosen = _browse_folder_native(start_dir)
        if chosen:
            path_edit.setText(chosen)

    btn_browse.clicked.connect(_do_browse)

    # Search -----------------------------------------------------------------
    def _do_search():
        mode = 'network' if rb_network.isChecked() else 'local'
        btn_search.setEnabled(False)
        progress.setVisible(True)
        search_status.setStyleSheet('')
        search_status.setText('Поиск...')

        w = _SearchWorker(mode, _LINUX_HINT, _SMB_PATH)

        def _on_status(msg):
            search_status.setText(msg)

        def _on_done(found):
            progress.setVisible(False)
            btn_search.setEnabled(True)
            if found:
                ok, reason_v = _validate_resource_repo(found)
                if ok:
                    path_edit.setText(found)
                    search_status.setText(f'Найдено: {found}')
                    search_status.setStyleSheet('color: green')
                    btn_ok.setEnabled(True)
                else:
                    search_status.setText(f'Найден каталог, но это не репозиторий: {reason_v}')
                    search_status.setStyleSheet('color: #b45309')
            else:
                search_status.setText('Репозиторий не найден. Укажите путь вручную.')
                search_status.setStyleSheet('color: red')

        w.status_update.connect(_on_status)
        w.result_ready.connect(_on_done)
        _worker[0] = w
        w.start()

    btn_search.clicked.connect(_do_search)

    # Create new (admin only) ------------------------------------------------
    if is_admin:
        def _do_create():
            p = path_edit.text().strip()
            if not p:
                verify_status.setText('Введите путь')
                verify_status.setStyleSheet('color: red')
                return
            if _init_new_resource_catalog(p):
                verify_status.setText('✓ Каталог создан')
                verify_status.setStyleSheet('color: green')
                btn_ok.setEnabled(True)
            else:
                verify_status.setText('✗ Не удалось создать каталог')
                verify_status.setStyleSheet('color: red')

        btn_create.clicked.connect(_do_create)

    # Accept / Cancel --------------------------------------------------------
    def _do_accept():
        _result[0] = path_edit.text().strip()
        dlg.accept()

    btn_ok.clicked.connect(_do_accept)
    btn_cancel.clicked.connect(dlg.reject)

    dlg.exec_()
    return _result[0]


def find_or_mount_linux_path(smb_path, hint='email-builder', status_callback=None,
                              resolved_path=None):
    """
    Searches for a mounted SMB share in ``/mnt`` and ``/media`` on Linux.

    Search order:

    0. ``resolved_path`` from config — exact path known from a previous run.
    1. Direct paths in ``/mnt`` and ``/media`` derived from the SMB URL components.
    2. Recursive ``**`` glob fallback across ``/mnt`` and ``/media``.

    :param smb_path: SMB URL, e.g. ``//server/share/subdir``.
    :param hint: Leaf folder name to locate, e.g. ``'email-builder'``.
    :param status_callback: Optional ``callable(str)`` for progress messages.
    :param resolved_path: Previously cached absolute path to try first.
    :returns: Absolute path string if found, otherwise ``None``.
    """
    import glob as _glob

    def status(msg):
        print(msg)
        if status_callback:
            status_callback(msg)

    # Strategy 0: previously resolved path stored in config.
    if resolved_path and os.path.exists(resolved_path):
        status('✓ Папка найдена (кеш конфига)')
        return resolved_path

    user = os.environ.get('USER', '*')

    # Parse SMB URL into share and subpath components for direct-path patterns.
    _share = _subpath = None
    if smb_path:
        _parts = smb_path.replace('\\', '/').lstrip('/').split('/')
        if len(_parts) >= 2:
            _share   = _parts[1]
            _subpath = '/'.join(_parts[2:]) if len(_parts) > 2 else hint

    def _first(*patterns, recursive=False):
        """Return the first existing path matching any of the glob patterns."""
        for p in patterns:
            hits = _glob.glob(p, recursive=recursive)
            if hits:
                return hits[0]
        return None

    status('Поиск в /mnt и /media...')

    # Strategy 1: direct paths — common /mnt and /media mount layouts.
    if _subpath:
        hit = _first(
            f'/mnt/{_subpath}',
            f'/mnt/{_share}/{_subpath}',
            f'/media/{user}/{_subpath}',
            f'/media/{user}/{_share}/{_subpath}',
            f'/media/{_subpath}',
            f'/media/{_share}/{_subpath}',
        )
        if hit:
            status('✓ Папка найдена')
            return hit

    # Strategy 2: recursive glob fallback.
    hit = _first(
        f'/mnt/**/{hint}',
        f'/media/**/{hint}',
        f'/media/{user}/**/{hint}',
        recursive=True,
    )
    if hit:
        status('✓ Папка найдена')
        return hit

    return None


def copy_directory_with_progress(src, dst, desc="Копирование"):
    """Копирование папки с отображением прогресса"""
    if not os.path.exists(src):
        print(f"⚠️  Папка не найдена: {src}")
        return False

    try:
        total_files = sum([len(files) for _, _, files in os.walk(src)])
        copied_files = 0

        print(f"📥 {desc}: {total_files} файлов...")

        for root, dirs, files in os.walk(src):
            rel_path = os.path.relpath(root, src)
            dst_dir = os.path.join(dst, rel_path)
            os.makedirs(dst_dir, exist_ok=True)

            for file in files:
                src_file = os.path.join(root, file)
                dst_file = os.path.join(dst_dir, file)
                shutil.copy2(src_file, dst_file)
                copied_files += 1

                if copied_files % 10 == 0 or copied_files == total_files:
                    progress = int((copied_files / total_files) * 100)
                    bar = '█' * (progress // 5) + '░' * (20 - progress // 5)
                    print(f"   [{bar}] {progress}%", end='\r')

        print(f"\n✓ {desc} завершено!")
        return True

    except Exception as e:
        print(f"❌ Ошибка копирования: {e}")
        return False


def initialize_cache():
    """Initialise (or refresh) the local asset cache from the network repo.

    Copies ``config.json`` and all static resource folders to ``CACHE_DIR``,
    then writes the network version to ``CACHE_VERSION_FILE``.

    Thread-safe: concurrent calls block on ``_cache_init_lock`` so only one
    initialisation runs at a time.  The caller that lost the race returns
    ``True`` immediately once the lock is released (the winner's run is
    assumed to have succeeded).

    :returns: ``True`` on success, ``False`` if network is unreachable.
    """
    if not _cache_init_lock.acquire(blocking=True, timeout=300):
        print('⏳ Ожидание завершения инициализации кеша...')
        return True
    try:
        return _initialize_cache_locked()
    finally:
        _cache_init_lock.release()


def _initialize_cache_locked():
    """Inner implementation of :func:`initialize_cache` (must hold _cache_init_lock)."""
    print("\n" + "=" * 60)
    print("🚀 Почтелье - Инициализация кеша")
    print("=" * 60)

    if not check_network_access():
        print("❌ ОШИБКА: Нет доступа к сетевой папке!")
        print(f"   Проверьте доступность: {NETWORK_RESOURCES_PATH}")
        show_error_dialog(
            'Почтелье — ошибка запуска',
            f'Нет доступа к сетевой папке:\n{NETWORK_RESOURCES_PATH}\n\n'
            'Локальный кеш не найден. Приложение не может запуститься.\n\n'
            'Проверьте подключение к сети и повторите попытку.'
        )
        return False

    # 1. Копируем config.json
    print("\n📥 Загрузка config.json...")
    network_config = os.path.join(
        NETWORK_RESOURCES_PATH, 'static', 'config.json')
    cache_config = os.path.join(CACHE_DIR, 'config.json')
    if os.path.exists(network_config):
        shutil.copy2(network_config, cache_config)
        print("✓ Config.json скопирован")

    # 2. Копируем только папки с картинками
    folders_to_cache = ['icons', 'expert-badges', 'bullets', 'button-icons',
                        'images', 'dividers', 'banner-backgrounds', 'banner-logos', 'banner-icons', 'fonts']
    for folder in folders_to_cache:
        network_folder = os.path.join(NETWORK_RESOURCES_PATH, 'static', folder)
        cache_folder = os.path.join(CACHE_DIR, folder)

        if os.path.exists(network_folder):
            print(f"\n📥 Загрузка {folder}/...")
            copy_directory_with_progress(network_folder, cache_folder, folder)

    # Сохраняем версию
    network_version = get_network_version()
    if network_version:
        set_cache_version(network_version)
        print(f"\n📝 Версия ресурсов: {network_version}")
    else:
        print("\n⚠️  Файл version.txt не найден на сервере")
        print("   Создаётся локальная версия...")
        import time as _time
        local_version = f"local-{_time.strftime('%Y%m%d')}"
        set_cache_version(local_version)
        print(f"📝 Версия ресурсов: {local_version}")

    print("=" * 60)
    print("✅ Инициализация завершена!")
    print("=" * 60 + "\n")
    return True


def check_for_updates():
    """Проверка обновлений при запуске. Не блокирует сервер — input() не используется."""
    print("🔍 Диагностика состояния кеша:")
    print(f"   CACHE_DIR: {CACHE_DIR}")
    print(f"   Существует: {os.path.exists(CACHE_DIR)}")

    cache_version = get_cache_version()
    print(f"   Версия кеша: {cache_version if cache_version else 'НЕ НАЙДЕНА'}")

    # Cache is considered valid if: version marker exists AND config.json was
    # copied.  We intentionally do NOT check for specific resource sub-folders
    # (icons, expert-badges, fonts, …) because their presence depends entirely
    # on the repository content — a repo without those folders would cause
    # initialize_cache() to run on every startup even though the cache is fine.
    cache_exists = os.path.exists(CACHE_DIR) and os.path.exists(
        os.path.join(CACHE_DIR, 'config.json'))

    if not cache_version or not cache_exists:
        if not cache_version:
            print("📦 Кеш не найден (отсутствует файл версии)")
        else:
            print("📦 Кеш не найден (отсутствует config.json)")
        print("   Требуется первичная инициализация")
        return initialize_cache()

    if not check_network_access():
        print("⚠️  Нет доступа к сетевому ресурсу")
        print("   Используется локальный кеш")
        show_error_dialog(
            'Почтелье — нет доступа к сети',
            f'Нет доступа к сетевой папке:\n{NETWORK_RESOURCES_PATH}\n\n'
            'Приложение запущено в автономном режиме.\n'
            'Шаблоны и ресурсы загружены из локального кеша.'
        )
        return True

    network_version = get_network_version()

    if not network_version:
        print("⚠️  Файл version.txt не найден на сервере")
        print("   Используется локальный кеш")
        return True

    if cache_version != network_version:
        print(f"📥 Обновление ресурсов: {cache_version} → {network_version}")
        return initialize_cache()

    print(f"✓ Ресурсы актуальны (версия {cache_version})")
    return True


# ============================================================================
# ФОНОВОЕ СКАНИРОВАНИЕ РЕПОЗИТОРИЯ
# ============================================================================

# Interval (seconds) between background repo scans.
_REPO_SCAN_INTERVAL: int = 60

_repo_snapshot_lock = threading.Lock()
_repo_snapshot: dict = {}  # {rel_path: fingerprint}


def _file_fingerprint(fpath: str) -> str:
    """Return a change-detection fingerprint for a single file.

    Uses ``mtime_ns:size`` for all file types.  This avoids reading file
    contents over the network on every scanner cycle while reliably detecting
    any modification (size change or timestamp update).  MD5 is not used here
    because the scanner only needs to *detect* changes, not verify content
    integrity — the atomic copy in :func:`_copy_if_changed` handles that.

    :param fpath: Absolute path to the file.
    :returns: Non-empty fingerprint string, or empty string on I/O error.
    """
    try:
        st = os.stat(fpath)
        return f'{st.st_mtime_ns}:{st.st_size}'
    except OSError:
        return ''


def _build_repo_snapshot() -> dict:
    """Scan the network repo and return ``{rel_path: fingerprint}`` for monitored files.

    Covers ``static/`` (all resource assets and config.json) and
    ``templates/shared/`` plus ``templates/categories.json``.
    Excludes ``version.txt`` — it is the change-signal itself and must
    not cause a recursive version bump when the scanner updates it.

    :returns: Mapping of relative path → fingerprint string.
    """
    snapshot: dict = {}
    base = NETWORK_RESOURCES_PATH
    if not os.path.isdir(base):
        return snapshot

    for scan_root in (
        os.path.join(base, 'static'),
        os.path.join(base, 'templates', 'shared'),
    ):
        if not os.path.isdir(scan_root):
            continue
        for dirpath, dirnames, filenames in os.walk(scan_root):
            dirnames.sort()
            for fname in sorted(filenames):
                fpath = os.path.join(dirpath, fname)
                fp = _file_fingerprint(fpath)
                if fp:
                    snapshot[os.path.relpath(fpath, base)] = fp

    categories_path = os.path.join(base, 'templates', 'categories.json')
    if os.path.isfile(categories_path):
        fp = _file_fingerprint(categories_path)
        if fp:
            snapshot[os.path.relpath(categories_path, base)] = fp

    return snapshot


def _repo_scanner_thread() -> None:
    """Background daemon: detect external repo changes and bump ``version.txt``.

    Runs in admin mode only.  Admin-UI mutations already call
    :func:`_bump_network_version` directly; this thread catches changes made
    by other tools (file managers, rsync, etc.) that bypass the admin UI.

    Change detection uses per-file fingerprints: MD5 for JSON/text files,
    ``mtime+size`` for binary assets.  When external changes are detected
    (outside the ``_REPO_SCAN_INTERVAL * 2`` window after the last admin
    mutation), :func:`_bump_network_version` is called and the in-memory
    template index is invalidated so the next request gets fresh data.
    """
    global _repo_snapshot, _admin_mutation_ts

    time.sleep(30)  # startup grace period: let initialize_cache() finish first
    with _repo_snapshot_lock:
        _repo_snapshot = _build_repo_snapshot()
        print(f'🔍 Сканер репо: начальный снимок ({len(_repo_snapshot)} файлов)')

    while True:
        time.sleep(_REPO_SCAN_INTERVAL)
        try:
            if not check_network_access():
                continue
            new_snapshot = _build_repo_snapshot()
            with _repo_snapshot_lock:
                old = _repo_snapshot
                if old and new_snapshot != old:
                    since_admin = time.time() - _admin_mutation_ts
                    if since_admin < _REPO_SCAN_INTERVAL:
                        # Changes are a follow-up from a recent admin UI mutation;
                        # silently update the snapshot without re-bumping version.
                        print('🔍 Сканер репо: изменения от UI-операции, снимок обновлён')
                    else:
                        added   = set(new_snapshot) - set(old)
                        removed = set(old) - set(new_snapshot)
                        changed = {k for k in set(new_snapshot) & set(old) if new_snapshot[k] != old[k]}
                        print(
                            f'🔄 Внешние изменения в репозитории: '
                            f'+{len(added)} / -{len(removed)} / ~{len(changed)} файлов'
                        )
                        _bump_network_version()
                        _invalidate_template_cache()
                _repo_snapshot = new_snapshot
        except Exception as exc:
            print(f'⚠️  Ошибка сканирования репозитория: {exc}')


def _copy_if_changed(src: str, dst: str) -> bool:
    """Copy *src* to *dst* atomically, only when the file has actually changed.

    Uses ``size + mtime`` as a fast "likely unchanged" guard.  When a copy is
    needed the data is written to a sibling temp file and then renamed into
    place with :func:`os.replace`, which is atomic on POSIX and best-effort
    atomic on Windows (NTFS).  The operation is therefore invisible to any
    concurrent reader: they see either the old file or the new file, never a
    partial write.

    :returns: ``True`` if the file was copied, ``False`` if it was skipped.
    """
    try:
        src_st = os.stat(src)
        if os.path.exists(dst):
            dst_st = os.stat(dst)
            # 2-second tolerance covers FAT32 mtime resolution and minor clock skew.
            if (dst_st.st_size == src_st.st_size
                    and abs(dst_st.st_mtime - src_st.st_mtime) < 2.0):
                return False  # almost certainly unchanged — skip

        dst_dir = os.path.dirname(dst)
        os.makedirs(dst_dir, exist_ok=True)
        fd, tmp_path = tempfile.mkstemp(dir=dst_dir)
        try:
            with os.fdopen(fd, 'wb') as fout:
                with open(src, 'rb') as fin:
                    shutil.copyfileobj(fin, fout)
            shutil.copystat(src, tmp_path)
            os.replace(tmp_path, dst)
        except Exception:
            try:
                os.unlink(tmp_path)
            except OSError:
                pass
            raise
        return True
    except OSError:
        return False


def _sync_dir_quiet(src: str, dst: str) -> int:
    """Incrementally sync *src* directory into *dst* using :func:`_copy_if_changed`.

    Only files at the top level of *src* are processed (no recursion needed
    for flat asset directories such as ``icons/`` or ``fonts/``).

    :returns: Number of files actually written.
    """
    if not os.path.isdir(src):
        return 0
    os.makedirs(dst, exist_ok=True)
    count = 0
    for fname in os.listdir(src):
        src_file = os.path.join(src, fname)
        if os.path.isfile(src_file):
            if _copy_if_changed(src_file, os.path.join(dst, fname)):
                count += 1
    return count


def _sync_cache_quiet() -> bool:
    """Incrementally sync the local asset cache from the network repo.

    Designed for background use — never shows dialogs, never blocks the Flask
    thread, and writes files atomically so ongoing HTTP responses are not
    disrupted.  During the sync the static file server continues serving the
    old cached versions; new versions become visible file-by-file as soon as
    each atomic rename completes.  ``config.json`` is updated *last* so the
    UI never sees a config that references icons not yet present in cache.

    Uses :data:`_cache_init_lock` with a non-blocking acquire: if
    :func:`initialize_cache` is already running (e.g. on startup), the
    background sync is skipped for this cycle rather than queuing behind it.

    :returns: ``True`` on success or when sync is already in progress,
              ``False`` if the network repo is unreachable.
    """
    if not _cache_init_lock.acquire(blocking=False):
        return True  # startup init is still running; skip this cycle

    try:
        if not check_network_access():
            return False

        os.makedirs(CACHE_DIR, exist_ok=True)
        static_src = os.path.join(NETWORK_RESOURCES_PATH, 'static')
        total = 0

        # Sync all asset folders first; config.json comes last.
        for folder in ('icons', 'expert-badges', 'bullets', 'button-icons',
                       'images', 'dividers', 'banner-backgrounds',
                       'banner-logos', 'banner-icons', 'fonts'):
            total += _sync_dir_quiet(
                os.path.join(static_src, folder),
                os.path.join(CACHE_DIR, folder),
            )

        # config.json is updated last: the UI always sees a config that is
        # consistent with the already-cached assets.
        cfg_src = os.path.join(static_src, 'config.json')
        if os.path.isfile(cfg_src):
            if _copy_if_changed(cfg_src, os.path.join(CACHE_DIR, 'config.json')):
                total += 1

        net_ver = get_network_version()
        if net_ver:
            set_cache_version(net_ver)

        if total:
            print(f'✓ Фоновое обновление кеша: {total} файлов синхронизировано')
        return True

    except Exception as exc:
        print(f'⚠️  Ошибка фоновой синхронизации кеша: {exc}')
        return False
    finally:
        _cache_init_lock.release()


def _cache_updater_thread() -> None:
    """Background daemon: keep the local asset cache in sync with the network repo.

    Runs in all modes.  Periodically compares the local cache version with
    the network ``version.txt``.  On a mismatch, calls :func:`_sync_cache_quiet`
    which copies only changed files atomically and never disrupts ongoing
    HTTP responses.
    """
    time.sleep(90)  # let startup initialisation complete before first check

    while True:
        time.sleep(_REPO_SCAN_INTERVAL)
        try:
            if not check_network_access():
                continue
            cache_ver = get_cache_version()
            net_ver   = get_network_version()
            if net_ver and cache_ver != net_ver:
                print(f'📥 Фоновое обновление кеша: {cache_ver} → {net_ver}')
                _sync_cache_quiet()
        except Exception as exc:
            print(f'⚠️  Ошибка автообновления кеша: {exc}')


def load_config():
    """
    Load config.json from the local cache (fast path) or from the network share
    as a fallback when the cache is absent.

    The cache is kept up-to-date by :func:`check_for_updates` / :func:`initialize_cache`
    on startup, so reading from the network on every API call is unnecessary and
    causes visible latency on Linux FUSE mounts (kio-fuse / gvfs).
    """
    cache_config_path   = os.path.join(CACHE_DIR, 'config.json')
    network_config_path = os.path.join(NETWORK_RESOURCES_PATH, 'static', 'config.json')

    # Fast path: local cache (milliseconds, no network).
    if os.path.exists(cache_config_path):
        try:
            with open(cache_config_path, 'r', encoding='utf-8') as f:
                return json.load(f)
        except Exception as e:
            print(f"⚠️  Ошибка чтения кеша config.json: {e}")

    # Fallback: network share (only when cache is missing, e.g. first run).
    if os.path.exists(network_config_path):
        try:
            with open(network_config_path, 'r', encoding='utf-8') as f:
                config = json.load(f)
            print("✓ Config.json загружен с сервера (кеш отсутствовал)")
            os.makedirs(os.path.dirname(cache_config_path), exist_ok=True)
            with open(cache_config_path, 'w', encoding='utf-8') as f:
                json.dump(config, f, ensure_ascii=False, indent=2)
            return config
        except Exception as e:
            print(f"⚠️  Ошибка чтения config.json с сервера: {e}")

    print("❌ Не удалось загрузить config.json!")
    return {"version": "1.0", "icons": {}, "expertBadges": [], "bullets": [], "buttonIcons": []}

# ============================================================================
# ФУНКЦИИ ОБРАБОТКИ ИЗОБРАЖЕНИЙ И ШРИФТОВ
# ============================================================================


def process_local_images_in_html(html_content, base_path=None):
    """Находит все <img src="путь_к_файлу"> в HTML и заменяет локальные файлы на base64"""
    if base_path is None:
        base_path = os.getcwd()

    img_pattern = re.compile(
        r'<img\s+([^>]*\s+)?src=["\'](?!(?:https?://|data:))([^"\']+)["\']([^>]*)>',
        re.IGNORECASE
    )

    def replace_image(match):
        try:
            before_attrs = match.group(1) or ''
            file_path = match.group(2)
            after_attrs = match.group(3) or ''

            if not os.path.isabs(file_path):
                file_path = os.path.normpath(
                    os.path.join(base_path, file_path))

            if not os.path.exists(file_path):
                print(f"⚠️  Изображение не найдено: {file_path}")
                return match.group(0)

            with open(file_path, 'rb') as img_file:
                img_data = img_file.read()
                img_base64 = base64.b64encode(img_data).decode('utf-8')

            mime_type, _ = mimetypes.guess_type(file_path)
            if mime_type is None:
                ext = os.path.splitext(file_path)[1].lower()
                mime_types = {
                    '.png': 'image/png',
                    '.jpg': 'image/jpeg',
                    '.jpeg': 'image/jpeg',
                    '.gif': 'image/gif',
                    '.bmp': 'image/bmp',
                    '.svg': 'image/svg+xml',
                }
                mime_type = mime_types.get(ext, 'image/png')

            data_uri = f"data:{mime_type};base64,{img_base64}"
            print(
                f"✓ Изображение конвертировано: {os.path.basename(file_path)}")

            return f'<img {before_attrs}src="{data_uri}"{after_attrs}>'

        except Exception as e:
            print(f"⚠️  Ошибка обработки изображения: {e}")
            return match.group(0)

    try:
        result = img_pattern.sub(replace_image, html_content)
        return result
    except Exception as e:
        print(f"⚠️  Ошибка обработки HTML: {e}")
        return html_content


def _parse_img_size_px(img_tag: str):
    """
    Вытаскивает width/height из тега <img ...>:
      - width="16" height="16"
      - style="width:16px; height:16px"
    Возвращает (w_px, h_px) или (None, None).
    """
    w = h = None
    m = re.search(
        r'\bwidth\s*=\s*["\']?\s*(\d+)\s*["\']?', img_tag, re.IGNORECASE)
    if m:
        w = int(m.group(1))
    m = re.search(
        r'\bheight\s*=\s*["\']?\s*(\d+)\s*["\']?', img_tag, re.IGNORECASE)
    if m:
        h = int(m.group(1))
    if w is None:
        m = re.search(r'width\s*:\s*(\d+)\s*px', img_tag, re.IGNORECASE)
        if m:
            w = int(m.group(1))
    if h is None:
        m = re.search(r'height\s*:\s*(\d+)\s*px', img_tag, re.IGNORECASE)
        if m:
            h = int(m.group(1))
    return w, h


def _get_local_ip() -> str:
    """Возвращает локальный IP машины (не 127.0.0.1)."""
    import socket
    try:
        s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        s.connect(('8.8.8.8', 80))
        ip = s.getsockname()[0]
        s.close()
        return ip
    except Exception:
        return '127.0.0.1'


def prepare_html_for_email(html_content: str) -> str:
    """
    Подготавливает HTML для отправки через Exchange.
    Заменяет все src на inline base64:
    - http://localhost:PORT/path  → ищет в CACHE_DIR / NETWORK / BASE_DIR
    - bullets/Буллет.png          → ищет в CACHE_DIR / NETWORK / BASE_DIR
    - data:...                    → оставляет как есть
    """
    if not html_content:
        return ''

    def resolve(rel_path: str):
        """Возвращает полный путь к файлу или None."""
        rel = rel_path.lstrip('/')
        for base in [CACHE_DIR,
                     os.path.join(NETWORK_RESOURCES_PATH, 'static'),
                     BUILTIN_DIR,
                     os.path.join(BUILTIN_DIR, 'static')]:
            p = os.path.join(base, rel)
            if os.path.exists(p):
                return p
        return None

    def to_base64(file_path: str, original: str) -> str:
        try:
            with open(file_path, 'rb') as f:
                data = f.read()
            mime_type, _ = mimetypes.guess_type(file_path)
            mime_type = mime_type or 'image/png'
            b64 = base64.b64encode(data).decode('utf-8')
            return f'src="data:{mime_type};base64,{b64}"'
        except Exception as e:
            print(f"⚠️  prepare_html: ошибка чтения {file_path}: {e}")
            return original

    # 1. localhost URL → base64
    def replace_localhost(match):
        full = match.group(0)
        url_path = match.group(1)
        fp = resolve(url_path)
        if not fp:
            print(f"⚠️  prepare_html: не найден: {url_path}")
            return full
        return to_base64(fp, full)

    html_content = re.sub(
        r'src="https?://(?:localhost|127\.0\.0\.1):\d+(/[^"]*)"',
        replace_localhost,
        html_content,
        flags=re.IGNORECASE
    )

    # 2. Относительные пути (bullets/..., dividers/..., banners/...) → base64
    RELATIVE_PREFIXES = (
        'bullets/', 'dividers/', 'icons/',
        'banner-backgrounds/', 'banner-logos/', 'banner-icons/',
        'button-icons/', 'expert-badges/', 'images/',
    )

    def replace_relative(match):
        full = match.group(0)
        src_val = match.group(1)
        if src_val.startswith('data:') or src_val.startswith('http'):
            return full
        if not any(src_val.startswith(p) for p in RELATIVE_PREFIXES):
            return full
        fp = resolve(src_val)
        if not fp:
            print(f"⚠️  prepare_html: не найден: {src_val}")
            return full
        return to_base64(fp, full)

    html_content = re.sub(
        r'src="([^"]+)"',
        replace_relative,
        html_content,
        flags=re.IGNORECASE
    )

    return html_content


def prepare_html_for_meeting(html_content: str) -> str:
    """
    Подготавливает HTML для встречи в Exchange Calendar.
    CalendarItem не поддерживает inline CID/base64.
    Все картинки (data: URI и относительные пути) конвертируем:
    - data:image → сохраняем как временный файл в CACHE_DIR/meeting-assets/
    - relative/path → http://IP:PORT/relative/path
    Outlook сам загружает картинки с нашего Flask-сервера.
    """
    if not html_content:
        return ''

    local_ip = _get_local_ip()
    base_url = f'http://{local_ip}:{PORT}'

    assets_dir = os.path.join(CACHE_DIR, 'meeting-assets')
    os.makedirs(assets_dir, exist_ok=True)

    RELATIVE_PREFIXES = (
        'bullets/', 'dividers/', 'icons/',
        'banner-backgrounds/', 'banner-logos/', 'banner-icons/',
        'button-icons/', 'expert-badges/', 'images/',
    )

    def replace_src(match):
        src_val = match.group(1)

        # data:image/... → сохраняем как временный файл
        dm = re.match(r'data:([^;]+);base64,(.+)', src_val, re.DOTALL)
        if dm:
            mime_type = dm.group(1)
            b64_data = dm.group(2).strip()
            try:
                raw = base64.b64decode(b64_data)
                ext = mimetypes.guess_extension(mime_type) or '.png'
                ext = ext.replace('.jpe', '.jpg')
                fname = f'{uuid.uuid4().hex}{ext}'
                fpath = os.path.join(assets_dir, fname)
                with open(fpath, 'wb') as f:
                    f.write(raw)
                return f'src="{base_url}/meeting-assets/{fname}"'
            except Exception as e:
                print(f'meeting asset error: {e}')
                return match.group(0)

        # localhost → реальный IP
        if 'localhost' in src_val or '127.0.0.1' in src_val:
            new_src = src_val.replace(f'http://localhost:{PORT}', base_url)
            new_src = new_src.replace(f'http://127.0.0.1:{PORT}', base_url)
            return f'src="{new_src}"'

        # Относительный путь → абсолютный URL
        if any(src_val.startswith(p) for p in RELATIVE_PREFIXES):
            return f'src="{base_url}/{src_val}"'

        return match.group(0)

    html_content = re.sub(
        r'src="([^"]+)"',
        replace_src,
        html_content,
        flags=re.IGNORECASE | re.DOTALL
    )
    return html_content


@app.route('/meeting-assets/<path:filename>')
def serve_meeting_asset(filename):
    """Отдаёт временные картинки встреч (для Outlook CalendarItem)."""
    assets_dir = os.path.join(CACHE_DIR, 'meeting-assets')
    return send_from_directory(assets_dir, filename)


@app.route('/')
def index():
    if APP_MODE == 'user':
        from flask import redirect
        return redirect('/user')
    return send_from_directory(app.static_folder, 'index.html')


@app.route('/user')
def user_index():
    """User-версия приложения"""
    return send_from_directory(app.static_folder, 'index-user.html')


@app.route('/data/<path:filename>', methods=['GET', 'HEAD'])
def static_data_files(filename):
    """Serve static JSON/data assets explicitly."""
    data_dir = os.path.join(app.static_folder, 'data')
    return send_from_directory(data_dir, filename)


@app.route('/protocol.log', methods=['GET', 'HEAD'])
def protocol_log_file():
    """Serve the active protocol.log file."""
    if not _ACTIVE_LOG_FILE or not os.path.exists(_ACTIVE_LOG_FILE):
        return abort(404)
    return send_file(_ACTIVE_LOG_FILE, mimetype='text/plain')


@app.route('/<path:path>', methods=['GET', 'HEAD'])
def static_files(path):
    """Гибридная раздача: картинки из кеша, остальное из static"""

    # Блокируем админские страницы/файлы в user-режиме
    if APP_MODE == 'user':
        blocked_paths = {
            'index.html',
        }
        # Блокируем все JS/CSS файлы которые относятся только к админке
        admin_js_prefixes = (
            'js/main.js',
            'js/settingsPanels.js',
            'js/settingsUI.js',
            'js/blockOperations.js',
            'js/columnOperations.js',
            'js/dragDrop.js',
            'js/canvasRenderer.js',
            'js/templatesUI.js',
            'js/themeToggle.js',
            'js/settings/',
        )
        if path in blocked_paths:
            abort(404)
        if any(path.startswith(p) for p in admin_js_prefixes):
            abort(404)

    # Общие ресурсы по явному URL /cache/{category}/{file}
    if path.startswith('cache/'):
        actual = path[len('cache/'):]
        cache_file = os.path.join(CACHE_DIR, actual)
        if os.path.exists(cache_file):
            return send_from_directory(CACHE_DIR, actual)
        network_file = os.path.join(NETWORK_RESOURCES_PATH, 'static', actual)
        if os.path.exists(network_file):
            return send_from_directory(os.path.join(NETWORK_RESOURCES_PATH, 'static'), actual)
        return 'File not found', 404

    # Картинки сначала ищем в кеше
    if path.startswith(('icons/', 'expert-badges/', 'bullets/', 'button-icons/', 'images/', 'banner-logos/', 'banner-backgrounds/', 'banner-icons/', 'dividers/', 'fonts/')):
        # Пробуем кеш
        cache_file = os.path.join(CACHE_DIR, path)
        if os.path.exists(cache_file):
            return send_from_directory(CACHE_DIR, path)

        # Fallback: пробуем сервер
        network_file = os.path.join(NETWORK_RESOURCES_PATH, 'static', path)
        if os.path.exists(network_file):
            print(f"⚠️  Файл не в кеше, загружаем с сервера: {path}")
            return send_from_directory(os.path.join(NETWORK_RESOURCES_PATH, 'static'), path)

        # Если нигде нет
        print(f"❌ Файл не найден: {path}")
        return "File not found", 404

    # HTML/CSS/JS из встроенной static
    return send_from_directory(app.static_folder, path)


def _merge_shared_resources_into_config(config: dict) -> dict:
    """
    Append shared resource files found in the local cache folders to *config*,
    adding only entries whose ``src`` URL is not already present.

    This handles files that were placed into the network resource folder directly
    (without going through the upload API) and therefore have no entry in
    ``config.json``.  The cache folder mirrors the network folder, so scanning it
    is both fast and offline-safe.
    """
    category_to_key = {
        'icons':              'icons.important',
        'expert-badges':      'expertBadges',
        'bullets':            'bullets',
        'button-icons':       'buttonIcons',
        'dividers':           'dividers',
        'banner-backgrounds': 'bannerBackgrounds',
        'banner-logos':       'bannerLogos',
        'banner-icons':       'bannerIcons',
        'images':             'images',
    }

    for category, key_path in category_to_key.items():
        cat_dir = os.path.join(CACHE_DIR, category)
        if not os.path.isdir(cat_dir):
            continue

        keys = key_path.split('.')
        node = config
        for k in keys[:-1]:
            node = node.setdefault(k, {})
        leaf_key = keys[-1]
        existing = node.get(leaf_key)
        if not isinstance(existing, list):
            existing = []

        existing_srcs = {item.get('src') for item in existing if isinstance(item, dict)}

        new_items = []
        for fname in sorted(os.listdir(cat_dir)):
            ext = os.path.splitext(fname)[1].lower()
            if ext not in _ALLOWED_IMAGE_EXTENSIONS:
                continue
            url = f'/cache/{category}/{fname}'
            if url not in existing_srcs:
                new_items.append({
                    'src': url,
                    'label': os.path.splitext(fname)[0],
                })

        if new_items:
            node[leaf_key] = existing + new_items

    return config


def _dedup_config_resources(config: dict) -> dict:
    """
    Deduplicate resource lists in *config* by the basename of each item's ``src``
    URL.  Items from earlier sources (shared config → shared cache → personal) are
    preferred; later duplicates are dropped.  This prevents the same physical file
    from appearing twice when it is referenced by different URL patterns
    (e.g. ``/cache/…`` vs ``/api/user-resources/file/…``).
    """
    list_keys = [
        ('icons', 'important'),
        ('expertBadges',),
        ('bullets',),
        ('buttonIcons',),
        ('dividers',),
        ('bannerBackgrounds',),
        ('bannerLogos',),
        ('bannerIcons',),
        ('images',),
    ]
    for key_path in list_keys:
        node = config
        for k in key_path[:-1]:
            if not isinstance(node, dict):
                break
            node = node.get(k, {})
        leaf = key_path[-1]
        if not isinstance(node, dict):
            continue
        items = node.get(leaf)
        if not isinstance(items, list):
            continue
        seen: set[str] = set()
        deduped = []
        for item in items:
            if not isinstance(item, dict):
                continue
            src = item.get('src', '')
            fname = src.rsplit('/', 1)[-1]
            if fname and fname in seen:
                continue
            if fname:
                seen.add(fname)
            deduped.append(item)
        node[leaf] = deduped
    return config


@app.route('/api/config', methods=['GET'])
def get_config():
    """API endpoint для получения конфигурации (config.json) с пользовательскими ресурсами."""
    try:
        config = load_config()
        config = _merge_shared_resources_into_config(config)
        config = _merge_user_resources_into_config(config)
        config = _dedup_config_resources(config)
        return jsonify({'success': True, 'config': config})
    except Exception as e:
        app.logger.error("get_config error: %s", e, exc_info=True)
        return jsonify({'success': False, 'error': 'Внутренняя ошибка сервера'}), 500


@app.route('/api/update-check', methods=['GET'])
def update_check():
    """
    Проверка наличия обновлений без блокировки.
    Возвращает: {'update_available': bool, 'current': str, 'new': str}
    Диалог обновления показывается в браузере, не в терминале.
    """
    try:
        current = get_cache_version() or 'unknown'

        if not check_network_access():
            return jsonify({
                'update_available': False,
                'current': current,
                'new': current,
                'reason': 'no_network'
            })

        network_version = get_network_version()
        if not network_version:
            return jsonify({
                'update_available': False,
                'current': current,
                'new': current,
                'reason': 'no_version_file'
            })

        update_available = (current != network_version)
        return jsonify({
            'update_available': update_available,
            'current': current,
            'new': network_version
        })

    except Exception as e:
        app.logger.error("update_check error: %s", e, exc_info=True)
        return jsonify({'update_available': False, 'error': 'Внутренняя ошибка сервера'}), 500


@app.route('/api/update-apply', methods=['POST'])
def update_apply():
    """
    Применить обновление ресурсов (вызывается из браузера после подтверждения).
    """
    try:
        if not check_network_access():
            return jsonify({'success': False, 'error': 'Нет доступа к сетевой папке'}), 503

        result = initialize_cache()
        if result:
            return jsonify({'success': True, 'version': get_cache_version()})
        else:
            return jsonify({'success': False, 'error': 'Обновление не удалось'}), 500

    except Exception as e:
        app.logger.error("update_apply error: %s", e, exc_info=True)
        return jsonify({'success': False, 'error': 'Внутренняя ошибка сервера'}), 500


# ============================================================================
# USER RESOURCES API
# ============================================================================

#: Categories that map to config.json array keys on the client side.
USER_RESOURCE_CATEGORIES = [
    'icons',
    'expert-badges',
    'bullets',
    'button-icons',
    'dividers',
    'banner-backgrounds',
    'banner-logos',
    'banner-icons',
    'images',
]

#: Allowed image file extensions for upload.
_ALLOWED_IMAGE_EXTENSIONS = {'.png', '.jpg', '.jpeg', '.gif', '.svg', '.webp'}


def get_user_resources_dir() -> str:
    """
    Returns the path to the personal user resources directory.

    Resources are stored locally so they are available offline and
    are private to the OS user account.

    Path: ``CACHE_BASE/user-resources/``
    """
    path = os.path.join(CACHE_BASE, 'user-resources')
    os.makedirs(path, exist_ok=True)
    return path


def _user_resource_url(category: str, filename: str) -> str:
    """Build the URL for serving a user-owned resource file."""
    return f'/api/user-resources/file/{category}/{filename}'


def _merge_user_resources_into_config(config: dict) -> dict:
    """
    Append user-owned resource items to the corresponding arrays in *config*.

    Each appended item has the ``userOwned`` flag set to ``True`` so the
    frontend can render a visual indicator.
    """
    base = get_user_resources_dir()

    # Mapping: filesystem category folder → config key path (dot-separated)
    category_to_key = {
        'icons':            'icons.important',
        'expert-badges':    'expertBadges',
        'bullets':          'bullets',
        'button-icons':     'buttonIcons',
        'dividers':         'dividers',
        'banner-backgrounds': 'bannerBackgrounds',
        'banner-logos':     'bannerLogos',
        'banner-icons':     'bannerIcons',
        'images':           'images',
    }

    for category, key_path in category_to_key.items():
        cat_dir = os.path.join(base, category)
        if not os.path.isdir(cat_dir):
            continue

        user_items = []
        for fname in sorted(os.listdir(cat_dir)):
            ext = os.path.splitext(fname)[1].lower()
            if ext not in _ALLOWED_IMAGE_EXTENSIONS:
                continue
            user_items.append({
                'src': _user_resource_url(category, fname),
                'label': os.path.splitext(fname)[0],
                'id': f'user-{category}-{fname}',
                'userOwned': True,
            })

        if not user_items:
            continue

        # Navigate / create the nested path in config
        keys = key_path.split('.')
        node = config
        for k in keys[:-1]:
            node = node.setdefault(k, {})
        leaf_key = keys[-1]
        existing = node.get(leaf_key)
        if not isinstance(existing, list):
            existing = []
        node[leaf_key] = existing + user_items

    return config


@app.route('/api/user-resources', methods=['GET'])
def user_resources_list():
    """
    List all user-owned resources grouped by category.

    Response: ``{success, resources: {category: [{filename, url, label}]}}``
    """
    try:
        base = get_user_resources_dir()
        result = {}
        for category in USER_RESOURCE_CATEGORIES:
            cat_dir = os.path.join(base, category)
            if not os.path.isdir(cat_dir):
                result[category] = []
                continue
            items = []
            for fname in sorted(os.listdir(cat_dir)):
                ext = os.path.splitext(fname)[1].lower()
                if ext not in _ALLOWED_IMAGE_EXTENSIONS:
                    continue
                items.append({
                    'filename': fname,
                    'url': _user_resource_url(category, fname),
                    'label': os.path.splitext(fname)[0],
                })
            result[category] = items
        return jsonify({'success': True, 'resources': result})
    except Exception as e:
        app.logger.error('user_resources_list error: %s', e, exc_info=True)
        return jsonify({'success': False, 'error': 'Внутренняя ошибка сервера'}), 500


@app.route('/api/user-resources/file/<category>/<filename>', methods=['GET'])
def user_resources_serve(category, filename):
    """Serve a single user-owned resource file."""
    if category not in USER_RESOURCE_CATEGORIES:
        abort(404)
    safe = secure_filename(filename)
    if not safe:
        abort(404)
    cat_dir = os.path.join(get_user_resources_dir(), category)
    return send_from_directory(cat_dir, safe)


@app.route('/api/user-resources/upload', methods=['POST'])
def user_resources_upload():
    """
    Upload a file to a user resource category.

    Form fields: ``category`` (string), ``file`` (multipart file).

    Response: ``{success, filename, url}``
    """
    try:
        category = request.form.get('category', '').strip()
        if category not in USER_RESOURCE_CATEGORIES:
            return jsonify({'success': False, 'error': 'Неверная категория'}), 400

        if 'file' not in request.files:
            return jsonify({'success': False, 'error': 'Файл не передан'}), 400

        f = request.files['file']
        if not f.filename:
            return jsonify({'success': False, 'error': 'Имя файла пустое'}), 400

        ext = os.path.splitext(f.filename)[1].lower()
        if ext not in _ALLOWED_IMAGE_EXTENSIONS:
            return jsonify({'success': False, 'error': 'Недопустимый тип файла'}), 400

        safe = secure_filename(f.filename)
        cat_dir = os.path.join(get_user_resources_dir(), category)
        os.makedirs(cat_dir, exist_ok=True)
        dest = os.path.join(cat_dir, safe)
        f.save(dest)

        return jsonify({
            'success': True,
            'filename': safe,
            'url': _user_resource_url(category, safe),
        })
    except Exception as e:
        app.logger.error('user_resources_upload error: %s', e, exc_info=True)
        return jsonify({'success': False, 'error': 'Внутренняя ошибка сервера'}), 500


@app.route('/api/user-resources/delete', methods=['DELETE'])
def user_resources_delete():
    """
    Delete a user-owned resource file.

    Query params: ``category``, ``filename``.

    Response: ``{success}``
    """
    try:
        category = request.args.get('category', '').strip()
        filename  = request.args.get('filename', '').strip()

        if category not in USER_RESOURCE_CATEGORIES:
            return jsonify({'success': False, 'error': 'Неверная категория'}), 400

        safe = secure_filename(filename)
        if not safe:
            return jsonify({'success': False, 'error': 'Неверное имя файла'}), 400

        path = os.path.join(get_user_resources_dir(), category, safe)
        if os.path.isfile(path):
            os.remove(path)

        return jsonify({'success': True})
    except Exception as e:
        app.logger.error('user_resources_delete error: %s', e, exc_info=True)
        return jsonify({'success': False, 'error': 'Внутренняя ошибка сервера'}), 500


@app.route('/api/user-resources/publish', methods=['POST'])
def user_resources_publish():
    """
    Publish a user-owned resource to the shared network repository (admin only).

    Copies the file to ``NETWORK_RESOURCES_PATH/static/{category}/`` and
    appends a matching entry to ``config.json`` if not already present.

    JSON body: ``{category, filename}``

    Response: ``{success}``
    """
    try:
        if APP_MODE != 'admin':
            return jsonify({'success': False, 'error': 'Недостаточно прав'}), 403

        data     = request.get_json(force=True) or {}
        category = data.get('category', '').strip()
        filename  = data.get('filename', '').strip()

        if category not in USER_RESOURCE_CATEGORIES:
            return jsonify({'success': False, 'error': 'Неверная категория'}), 400

        safe = secure_filename(filename)
        if not safe:
            return jsonify({'success': False, 'error': 'Неверное имя файла'}), 400

        src_path = os.path.join(get_user_resources_dir(), category, safe)
        if not os.path.isfile(src_path):
            return jsonify({'success': False, 'error': 'Файл не найден'}), 404

        dest_dir = os.path.join(NETWORK_RESOURCES_PATH, 'static', category)
        os.makedirs(dest_dir, exist_ok=True)
        dest_path = os.path.join(dest_dir, safe)
        shutil.copy2(src_path, dest_path)

        pub_url = f'/cache/{category}/{safe}'
        _append_to_config_json(category, safe, pub_url)
        _bump_network_version()

        return jsonify({'success': True})
    except Exception as e:
        app.logger.error('user_resources_publish error: %s', e, exc_info=True)
        return jsonify({'success': False, 'error': 'Внутренняя ошибка сервера'}), 500


